/**
 * Build guard: fail loudly when a marketing image master has been replaced but
 * its derivatives were never regenerated.
 *
 * This exists because the derivatives are generated by a separate Pillow script,
 * so nothing otherwise connects "designer drops a new .webp into assets/other"
 * to "the site shows the new picture". The check compares each master's sha256
 * against `src/assets/marketing/.manifest.json` — content, not filename, not
 * mtime — and refuses to build a bundle that would ship a stale crop.
 *
 * Runs as npm's `prebuild`. On CI/Vercel the masters are not uploaded
 * (.vercelignore) and the committed derivatives are authoritative, so the check
 * skips itself when assets/other is absent.
 */
import { createHash } from "node:crypto";
import { existsSync, readFileSync, readdirSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const mastersDir = join(root, "assets", "other");
// Every generated set: each has its own output dir + content manifest.
const outDirs = [join(root, "src", "assets", "marketing"), join(root, "src", "assets", "auth")];

if (!existsSync(mastersDir)) {
  console.log("[images] masters not present (CI) — using committed derivatives.");
  process.exit(0);
}

// stem -> { sha256, outputs, dir }
const manifest = {};
for (const dir of outDirs) {
  const path = join(dir, ".manifest.json");
  if (!existsSync(path)) continue;
  for (const [stem, entry] of Object.entries(JSON.parse(readFileSync(path, "utf8")))) {
    manifest[stem] = { ...entry, dir };
  }
}
const sha = (p) => createHash("sha256").update(readFileSync(p)).digest("hex");

const problems = [];

// Hero slides: masters are `<name>_{wide,mobile}.png`, hashed as a pair, with the
// manifest kept beside them (never shipped in public/).
const heroDir = join(root, "assets", "home");
const heroOut = join(root, "src", "assets", "home");
if (existsSync(heroDir)) {
  const heroManifestPath = join(heroDir, ".manifest.json");
  const heroManifest = existsSync(heroManifestPath)
    ? JSON.parse(readFileSync(heroManifestPath, "utf8"))
    : {};
  for (const file of readdirSync(heroDir)) {
    const ext = file.endsWith("_wide.webp") ? ".webp" : file.endsWith("_wide.png") ? ".png" : null;
    if (!ext) continue;
    const stem = file.slice(0, -`_wide${ext}`.length);
    const entry = heroManifest[stem];
    if (!entry) continue;
    const mobile = join(heroDir, `${stem}_mobile${ext}`);
    if (!existsSync(mobile)) continue;
    if (entry.sha256 !== sha(join(heroDir, file)) + sha(mobile)) {
      problems.push(`${stem}_{wide,mobile}.png was replaced — its hero derivatives are stale`);
      continue;
    }
    const missing = (entry.outputs ?? []).filter((o) => !existsSync(join(heroOut, o)));
    if (missing.length) problems.push(`${stem} is missing hero derivatives: ${missing.join(", ")}`);
  }
}

for (const file of readdirSync(mastersDir)) {
  if (!file.endsWith(".webp")) continue;
  const stem = file.slice(0, -".webp".length);
  const entry = manifest[stem];
  // Masters that no page consumes (spare crops, alternates) are ignored.
  if (!entry) continue;

  if (entry.sha256 !== sha(join(mastersDir, file))) {
    problems.push(`${file} was replaced — its derivatives are stale`);
    continue;
  }
  const missing = (entry.outputs ?? []).filter((o) => !existsSync(join(entry.dir, o)));
  if (missing.length) problems.push(`${file} is missing derivatives: ${missing.join(", ")}`);
}

if (problems.length) {
  console.error("\n[images] BUILD BLOCKED — marketing derivatives are out of date:\n");
  for (const p of problems) console.error(`  • ${p}`);
  console.error("\n  Fix: python scripts/gen-marketing-images.py\n");
  process.exit(1);
}

console.log(`[images] all derivatives match their masters (${Object.keys(manifest).length} masters).`);
